// src/pages/ResultsPage.js
import React, { useEffect, useRef, useState } from "react";
import { saveSession } from "../utils/firebase";
import "./ResultsPage.css";

// ── Highlighted transcript ────────────────────────────────────────────────────
function HighlightedTranscript({ transcript, fillerCounts, lowConfidenceWords }) {
  if (!transcript) return <span>No transcript available.</span>;
  const fillerSet = new Set(Object.keys(fillerCounts).map(w => w.toLowerCase()));
  const lowConfSet = new Set((lowConfidenceWords || []).map(w => w.word.toLowerCase()));
  const tokens = transcript.split(/(\s+)/);
  return (
    <span>
      {tokens.map((token, i) => {
        const clean = token.toLowerCase().replace(/[^a-z]/g, "").trim();
        if (!clean) return <span key={i}>{token}</span>;
        if (fillerSet.has(clean))
          return <mark key={i} className="highlight-filler" title="Filler word">{token}</mark>;
        if (lowConfSet.has(clean))
          return <mark key={i} className="highlight-pronunciation" title="Possible mispronunciation">{token}</mark>;
        return <span key={i}>{token}</span>;
      })}
    </span>
  );
}

// ── Formatted feedback with section headers ───────────────────────────────────
function FormattedFeedback({ feedback }) {
  if (!feedback) return null;
  const lines = feedback.split("\n").filter(Boolean);
  return (
    <div className="feedback-sections">
      {lines.map((line, i) => {
        const isHeader = line.startsWith("**") && line.endsWith("**");
        if (isHeader) return <p key={i} className="feedback-section-header">{line.replace(/\*\*/g, "")}</p>;
        const parts = line.split(/(\*\*[^*]+\*\*)/g);
        return (
          <p key={i} className="feedback-para">
            {parts.map((part, j) =>
              part.startsWith("**") && part.endsWith("**")
                ? <strong key={j}>{part.replace(/\*\*/g, "")}</strong>
                : part
            )}
          </p>
        );
      })}
    </div>
  );
}

// ── Score ring ────────────────────────────────────────────────────────────────
function ScoreRing({ score }) {
  const r = 54;
  const circ = 2 * Math.PI * r;
  const offset = circ - (score / 100) * circ;
  const color = score >= 80 ? "#4ecca3" : score >= 65 ? "#ffd166" : "#fc6c8f";
  const label = score >= 80 ? "Excellent" : score >= 65 ? "Good" : score >= 50 ? "Fair" : "Needs Work";
  return (
    <div className="score-ring-wrap">
      <div className="score-ring">
        <svg viewBox="0 0 120 120" width="120" height="120">
          <circle className="score-ring-bg" cx="60" cy="60" r={r} />
          <circle className="score-ring-fill" cx="60" cy="60" r={r}
            strokeDasharray={circ} strokeDashoffset={offset} stroke={color} />
        </svg>
        <div className="score-ring-text">
          <span className="score-num" style={{ color }}>{score}</span>
          <span className="score-label">/ 100</span>
        </div>
      </div>
      <span className="tag" style={{ background: `${color}22`, color }}>{label}</span>
    </div>
  );
}

// ── Metric card ───────────────────────────────────────────────────────────────
function MetricCard({ label, value, unit, note, color = "#7c6cfc" }) {
  return (
    <div className="metric-card card">
      <span className="metric-value" style={{ color }}>{value}</span>
      <span className="metric-unit">{unit}</span>
      <span className="metric-label">{label}</span>
      {note && <span className="metric-note">{note}</span>}
    </div>
  );
}

// ── Pronunciation coach — fully dynamic from Claude ───────────────────────────
function PronunciationCoach({ pronunciationTips, lowConfidenceWords, avgConfidence }) {
  const [expanded, setExpanded] = useState(null);
  const hasTips = pronunciationTips && pronunciationTips.length > 0;
  const hasFlags = lowConfidenceWords && lowConfidenceWords.length > 0;

  const getConfidenceColor = (prob) =>
    prob >= 75 ? "#ffd166" : prob >= 50 ? "#fc8c4a" : "#fc6c8f";

  return (
    <div className="card pronunciation-card">
      <div className="feedback-header">
        <span className="feedback-icon">🗣️</span>
        <div>
          <h3>Pronunciation Coach</h3>
          <p className="feedback-sub">
            Analyzed from your actual speech · Clarity score: {avgConfidence}%
          </p>
        </div>
      </div>

      {/* Flagged words from Whisper */}
      {hasFlags && (
        <div className="mispronounced-section">
          <p className="mispronounced-intro">
            These words were <strong>unclear in your recording</strong> — lower % means harder to understand:
          </p>
          <div className="mispronounced-grid">
            {lowConfidenceWords.map((w, i) => (
              <div key={i} className="mispronounced-chip"
                style={{ borderColor: getConfidenceColor(w.prob) }}>
                <span className="mis-word">"{w.word}"</span>
                <span className="mis-prob" style={{ color: getConfidenceColor(w.prob) }}>{w.prob}%</span>
                <span className="mis-label" style={{ color: getConfidenceColor(w.prob) }}>
                  {w.prob >= 75 ? "Slight issue" : w.prob >= 50 ? "Unclear" : "Hard to hear"}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {!hasFlags && (
        <div className="pronunciation-clean">
          <span className="clean-icon">✅</span>
          <p>No significant pronunciation issues detected. Your words were clear and easy to understand!</p>
        </div>
      )}

      {/* Dynamic tips from Claude based on actual transcript */}
      {hasTips && (
        <div className="pron-tips-section">
          <p className="tips-label">💬 Based on what you said — specific corrections:</p>
          <div className="pron-tips-list">
            {pronunciationTips.map((tip, i) => (
              <div key={i} className={`pron-tip-card ${expanded === i ? "expanded" : ""}`}
                onClick={() => setExpanded(expanded === i ? null : i)}>
                <div className="pron-tip-header">
                  <div className="pron-tip-left">
                    <span className="pron-tip-word">"{tip.word}"</span>
                    <span className="pron-tip-issue">{tip.issue}</span>
                  </div>
                  <span className="pron-tip-toggle">{expanded === i ? "▲" : "▼"}</span>
                </div>
                {expanded === i && (
                  <div className="pron-tip-body">
                    <div className="pron-detail">
                      <span className="pron-detail-label">✅ Correct pronunciation</span>
                      <span className="pron-detail-value correct">{tip.correct}</span>
                    </div>
                    <div className="pron-detail">
                      <span className="pron-detail-label">💡 Quick fix</span>
                      <span className="pron-detail-value">{tip.tip}</span>
                    </div>
                    {tip.example && (
                      <div className="pron-detail">
                        <span className="pron-detail-label">📖 Example</span>
                        <span className="pron-detail-value example">"{tip.example}"</span>
                      </div>
                    )}
                    <a
                      href={`https://youglish.com/pronounce/${encodeURIComponent(tip.word)}/english`}
                      target="_blank"
                      rel="noreferrer"
                      className="youglish-link"
                      onClick={e => e.stopPropagation()}
                    >
                      🔊 Hear it on YouGlish →
                    </a>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {!hasTips && !hasFlags && (
        <p className="pron-no-tips">Your pronunciation was great overall! Keep practicing to maintain this level.</p>
      )}
    </div>
  );
}

// ── Main Results Page ─────────────────────────────────────────────────────────
export default function ResultsPage({ navigate, results }) {
  const { transcript, metrics, feedback, pronunciationTips, scenario } = results || {};
  const saved = useRef(false);

  useEffect(() => {
    if (!saved.current && metrics) {
      saved.current = true;
      saveSession({ scenario, transcript, metrics, feedback, date: new Date().toISOString() });
    }
  }, []);

  if (!results) return <div className="results-page center"><p>No results found.</p></div>;

  const wpmColor   = metrics.wpm >= 120 && metrics.wpm <= 160 ? "#4ecca3" : metrics.wpm > 160 ? "#fc6c8f" : "#ffd166";
  const fillerColor = metrics.totalFillers === 0 ? "#4ecca3" : metrics.totalFillers <= 5 ? "#ffd166" : "#fc6c8f";
  const scoreColor  = metrics.score >= 80 ? "#4ecca3" : metrics.score >= 65 ? "#ffd166" : "#fc6c8f";
  const pronColor   = metrics.avgConfidence >= 85 ? "#4ecca3" : metrics.avgConfidence >= 70 ? "#ffd166" : "#fc6c8f";

  const hasFillers = Object.keys(metrics.fillerCounts).length > 0;
  const hasPron    = metrics.lowConfidenceWords?.length > 0;

  return (
    <div className="results-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>📊 Dashboard</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
        </div>
      </nav>

      <div className="results-inner">

        {/* Header */}
        <div className="results-header">
          <span className="tag tag-purple">{scenario}</span>
          <h1>Your Results</h1>
          <p className="results-date">{new Date().toLocaleDateString("en-PH", { month: "long", day: "numeric", year: "numeric" })}</p>
        </div>

        {/* ① TRANSCRIPT — first so they see what they said */}
        <div className="card transcript-section">
          <div className="transcript-header-row">
            <span className="transcript-title">📝 Your Transcript</span>
            <div className="transcript-legend">
              {hasFillers && <span><mark className="legend-mark filler-legend">filler word</mark></span>}
              {hasPron    && <span><mark className="legend-mark pronunciation-legend">unclear word</mark></span>}
            </div>
          </div>
          <div className="transcript-body-open">
            <HighlightedTranscript
              transcript={transcript}
              fillerCounts={metrics.fillerCounts}
              lowConfidenceWords={metrics.lowConfidenceWords}
            />
          </div>
        </div>

        {/* ② SCORE + METRICS */}
        <div className="score-row">
          <ScoreRing score={metrics.score} />
          <div className="metrics-grid">
            <MetricCard label="Speech Rate"    value={metrics.wpm}             unit="WPM"      color={wpmColor}    note={metrics.wpm > 160 ? "Too fast" : metrics.wpm < 100 ? "Too slow" : "Perfect pace!"} />
            <MetricCard label="Pronunciation"  value={metrics.avgConfidence}   unit="% clear"  color={pronColor}   note={metrics.avgConfidence >= 85 ? "Very clear!" : metrics.avgConfidence >= 70 ? "Mostly clear" : "Needs work"} />
            <MetricCard label="Filler Words"   value={metrics.totalFillers}    unit="fillers"  color={fillerColor} note={metrics.totalFillers === 0 ? "Perfect!" : metrics.totalFillers <= 5 ? "Good job!" : "Try pausing"} />
            <MetricCard label="Vocabulary"     value={metrics.vocabularyRatio} unit="% unique" color="#a99dff"     note={metrics.vocabularyRatio >= 70 ? "Rich vocab!" : "Try more variety"} />
          </div>
        </div>

        {/* ③ FILLER BREAKDOWN */}
        {hasFillers && (
          <div className="card filler-section">
            <h3 className="section-h3">🔍 Filler Word Breakdown</h3>
            <div className="filler-chips">
              {Object.entries(metrics.fillerCounts).sort((a, b) => b[1] - a[1]).map(([word, count]) => (
                <div key={word} className="filler-chip">
                  <span className="filler-word">"{word}"</span>
                  <span className="filler-count">{count}×</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ④ AI COACHING FEEDBACK */}
        <div className="card feedback-card">
          <div className="feedback-header">
            <span className="feedback-icon">🤖</span>
            <div>
              <h3>AI Coaching Feedback</h3>
              <p className="feedback-sub">Personalized insights powered by Claude</p>
            </div>
          </div>
          <div className="feedback-body">
            <FormattedFeedback feedback={feedback} />
          </div>
        </div>

        {/* ⑤ PRONUNCIATION COACH */}
        <PronunciationCoach
          pronunciationTips={pronunciationTips}
          lowConfidenceWords={metrics.lowConfidenceWords}
          avgConfidence={metrics.avgConfidence}
        />

        {/* Actions */}
        <div className="results-actions">
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
          <button className="btn btn-outline" onClick={() => navigate("dashboard")}>📈 View Progress</button>
        </div>

      </div>
    </div>
  );
}
